/* -------------------------------------------------------------------- */
/* Poll generator (UK only)                                             */
/* -------------------------------------------------------------------- */

/** Centre-of-mass per party (in %). Polls jitter around this and drift slowly. */
const center: Record<string, number> = {
  "reform-uk": 26.0,
  labour: 24.0,
  conservative: 20.0,
  "liberal-democrats": 13.0,
  "green-party": 8.0,
  snp: 2.6,
  "plaid-cymru": 0.7,
  others: 5.7,
};

/** Net drift from a year ago to today (towards "now"). */
const drift: Record<string, number> = {
  "reform-uk": +6.0,
  labour: -7.0,
  conservative: -2.5,
  "liberal-democrats": +0.5,
  "green-party": +1.5,
  snp: -0.5,
  "plaid-cymru": 0,
  others: +2.0,
};

function mulberry32(seed: number) {
  return function () {
    seed |= 0;
    seed = (seed + 0x6d2b79f5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function generatePolls(): Poll[] {
  const rng = mulberry32(20260621);
  const out: Poll[] = [];
  const today = new Date(AS_OF);
  const polledIds = Object.keys(center);
  let idx = 0;
  // 40 polls across ~12 months, cycling through institutes
  for (let i = 0; i < 40; i++) {
    const inst = institutes[i % institutes.length];
    const daysAgo = Math.floor(i * 9 + rng() * 5);
    const fieldworkEnd = new Date(today);
    fieldworkEnd.setDate(fieldworkEnd.getDate() - daysAgo);
    const publishDate = new Date(fieldworkEnd);
    publishDate.setDate(publishDate.getDate() + 2);
    const phase = 1 - i / 40; // 1 = today, 0 = oldest
    const raw: Record<string, number> = {};
    let sum = 0;
    for (const id of polledIds) {
      const noise = (rng() - 0.5) * 2.6;
      const val = Math.max(0.3, center[id] + drift[id] * phase + noise - drift[id] * 0.5);
      raw[id] = val;
      sum += val;
    }
    const norm: Record<string, number> = {};
    for (const k of Object.keys(raw)) norm[k] = +((raw[k] * 100) / sum).toFixed(1);
    out.push({
      id: `uk-poll-${++idx}`,
      countryCode: "united-kingdom",
      instituteId: inst.id,
      fieldworkEnd: fieldworkEnd.toISOString().slice(0, 10),
      publishDate: publishDate.toISOString().slice(0, 10),
      sampleSize: 1000 + Math.floor(rng() * 1400),
      electionType: "national",
      results: norm,
    });
  }
  return out.sort((a, b) => b.fieldworkEnd.localeCompare(a.fieldworkEnd));
}

export const polls: Poll[] = generatePolls();

