/* -------------------------------------------------------------------- */
/* Helpers                                                              */
/* -------------------------------------------------------------------- */

export function partiesByCountry(_code?: string) {
  return parties.filter((p) => p.countryCode === "united-kingdom");
}
export function activeParties() {
  return parties.filter((p) => !p.historical);
}
export function historicalParties() {
  return parties.filter((p) => p.historical);
}
export function polledParties() {
  return parties.filter((p) => p.inPolls);
}
export function institutesByCountry(_code?: string) {
  return institutes;
}
export function pollsByCountry(_code?: string) {
  return polls;
}
export function countryByCode(_code?: string) {
  return country;
}
export function partyById(id: string) {
  return parties.find((p) => p.id === id);
}
export function instituteById(id: string) {
  return institutes.find((i) => i.id === id);
}
